import type { SearchInputConfig } from '@linm-soft-org/linm-web-common-components';
import { tscdService } from '../../services/tscd/tscdService';
import type { FixedAssetDto } from '../../services/tscd/models';
import {
  SEARCH_DROPDOWN_CODE_WIDTH,
  SEARCH_DROPDOWN_PORTAL,
  SEARCH_DROPDOWN_PRIMARY_WIDTH,
} from './searchDropdownDefaults';

/** SearchInput config for fixed assets (TSCĐ) */
export function createFixedAssetSearchConfig(): SearchInputConfig<FixedAssetDto> {
  return {
    api: {
      getItemKey: (a) => a.id,
      search: async ({ search, page, pageSize }) => {
        const items = await tscdService.searchAssets({ search, page, pageSize, lifecycle: 'Active' });
        const totalPages = Math.max(1, Math.ceil(items.length / pageSize));
        return { items, page, totalPages };
      },
      getDetail: (id) => tscdService.getAsset(id),
    },
    display: {
      getPrimaryDisplay: (a) => a.code,
      getSecondaryDisplay: (a) => a.name,
      getSingleDisplay: (a) => a.name,
    },
    columns: [
      { key: 'code', variant: 'badge', width: SEARCH_DROPDOWN_CODE_WIDTH, render: (a) => a.code },
      { key: 'name', variant: 'primary', width: SEARCH_DROPDOWN_PRIMARY_WIDTH, render: (a) => a.name },
      {
        key: 'bookValue',
        variant: 'meta',
        render: (a) => a.bookValue.toLocaleString('vi-VN'),
      },
    ],
    header: {
      columns: [
        { key: 'code', label: 'Mã TSCĐ' },
        { key: 'name', label: 'Tên tài sản' },
        { key: 'bookValue', label: 'GT còn lại' },
      ],
    },
    texts: {
      secondaryPlaceholder: 'Tên tài sản',
      empty: 'Không tìm thấy TSCĐ',
    },
    ...SEARCH_DROPDOWN_PORTAL,
  };
}
