import type { SearchInputConfig } from '@linm-soft-org/linm-web-common-components';
import { ktService } from '../../services/kt/ktService';
import type { UnpaidInvoiceDto } from '../../services/kt/models';
import { formatMoneyVnd } from '../../utils/formatters';
import {
  SEARCH_DROPDOWN_CODE_WIDTH,
  SEARCH_DROPDOWN_PORTAL,
  SEARCH_DROPDOWN_PRIMARY_WIDTH,
} from './searchDropdownDefaults';

/** SEARCH_REMOTE — hóa đơn bán hàng chưa thanh toán (`GET /receipts/unpaid-invoices`). */
export function createSalesInvoiceSearchConfig(
  customerId: string,
): SearchInputConfig<UnpaidInvoiceDto> {
  return {
    api: {
      getItemKey: (inv) => inv.id,
      search: async ({ search, page, pageSize }) => {
        const items = await ktService.getUnpaidInvoices(customerId);
        const term = (search ?? '').trim().toLowerCase();
        const filtered = term
          ? items.filter((i) => i.code.toLowerCase().includes(term))
          : items;
        const totalPages = Math.max(1, Math.ceil(filtered.length / pageSize));
        const start = (page - 1) * pageSize;
        return { items: filtered.slice(start, start + pageSize), page, totalPages };
      },
    },
    display: {
      getPrimaryDisplay: (inv) => inv.code,
      getSecondaryDisplay: (inv) => `${formatMoneyVnd(inv.totalAmount)}`,
      getSingleDisplay: (inv) => `${inv.code} — ${formatMoneyVnd(inv.totalAmount)}`,
    },
    columns: [
      { key: 'code', variant: 'badge', width: SEARCH_DROPDOWN_CODE_WIDTH, render: (inv) => inv.code },
      {
        key: 'date',
        variant: 'primary',
        width: '6rem',
        render: (inv) => inv.invoiceDate,
      },
      {
        key: 'amount',
        variant: 'meta',
        width: SEARCH_DROPDOWN_PRIMARY_WIDTH,
        align: 'end',
        render: (inv) => formatMoneyVnd(inv.totalAmount),
      },
      {
        key: 'remaining',
        variant: 'meta',
        width: '7rem',
        align: 'end',
        render: (inv) => formatMoneyVnd(inv.remainingAmount),
      },
    ],
    header: {
      columns: [
        { key: 'code', label: 'Số hóa đơn' },
        { key: 'date', label: 'Ngày' },
        { key: 'amount', label: 'Tiền HĐ' },
        { key: 'remaining', label: 'Còn lại' },
      ],
    },
    texts: {
      secondaryPlaceholder: 'Tiền HĐ',
      empty: 'Không tìm thấy hóa đơn',
    },
    ...SEARCH_DROPDOWN_PORTAL,
  };
}
